// Store audit results in workflow static data for polling
const sd = $getWorkflowStaticData('global');
const jobId = $('URL Validator').first().json.jobId;
const frontendData = $json.frontendData;

// Store with TTL timestamp (2 hours)
sd[jobId] = JSON.stringify({
  status: 'done',
  data: frontendData,
  storedAt: Date.now(),
  expiresAt: Date.now() + (2 * 60 * 60 * 1000) // 2h TTL
});

// Cleanup: remove expired results (older than 2 hours)
const now = Date.now();
for (const key of Object.keys(sd)) {
  if (key.startsWith('job_')) {
    try {
      const entry = JSON.parse(sd[key]);
      if (entry.expiresAt && entry.expiresAt < now) {
        delete sd[key];
      }
    } catch(e) {
      // Also clean rate limit keys older than current hour
      if (key.startsWith('rl:')) {
        const hour = Math.floor(now / (60*60*1000));
        const keyHour = parseInt(key.split(':')[2] || '0');
        if (keyHour < hour - 1) delete sd[key];
      }
    }
  }
}

return [{ json: { stored: true, jobId, email: $json.email, domain: $json.domain } }];

// Look up audit results by jobId
const sd = $getWorkflowStaticData('global');

// Query-Parameter aus Webhook holen (n8n v2)
const jobId = $('Webhook Status').first().json.query?.jobId 
           || $('Webhook Status').first().json.params?.jobId 
           || '';

if (!jobId || !jobId.startsWith('job_')) {
  return [{ json: { ok: false, status: 'error', error: 'Ungültige Job-ID.' } }];
}

const raw = sd[jobId];
if (!raw) {
  return [{ json: { ok: true, status: 'processing', jobId, message: 'Audit läuft noch...' } }];
}

try {
  const entry = JSON.parse(raw);
  if (entry.expiresAt && entry.expiresAt < Date.now()) {
    delete sd[jobId];
    return [{ json: { ok: false, status: 'expired', error: 'Ergebnis abgelaufen.' } }];
  }
  return [{ json: { ok: true, status: 'done', jobId, data: entry.data } }];
} catch(e) {
  return [{ json: { ok: false, status: 'error', error: 'Fehler beim Laden.' } }];
}
